import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { 
  Home, 
  FileText, 
  Scale, 
  Calculator, 
  Menu, 
  X, 
  ChevronDown, 
  ChevronUp 
} from 'lucide-react';
import { useAuth } from '../context/AuthContext';

const Layout = ({ children }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [expandedMenus, setExpandedMenus] = useState({});
  const location = useLocation();
  const { logout } = useAuth();

  const navigation = [
    { 
      name: 'General', 
      type: 'header' 
    },
    { 
      name: 'Home', 
      href: '/home', 
      icon: Home 
    },
    { 
      name: 'Components', 
      icon: 'ri-vip-diamond-fill',
      badge: { text: 'Hot', type: 'primary' },
      submenu: [
        { name: 'Grid', href: '/grid' },
        { name: 'Layout', href: '/layout' },
        { 
          name: 'Forms', 
          submenu: [
            { name: 'Input', href: '/forms/input' },
            { name: 'Select', href: '/forms/select' },
            { 
              name: 'More', 
              submenu: [
                { name: 'CheckBox', href: '/forms/checkbox' },
                { name: 'Radio', href: '/forms/radio' }
              ]
            }
          ]
        }
      ]
    },
    { 
      name: 'Charts', 
      icon: 'ri-bar-chart-2-fill',
      submenu: [
        { name: 'Pie chart', href: '/charts/pie' },
        { name: 'Line chart', href: '/charts/line' },
        { name: 'Bar chart', href: '/charts/bar' }
      ]
    },
    { 
      name: 'E-commerce', 
      icon: 'ri-shopping-cart-fill',
      submenu: [
        { name: 'Products', href: '/ecommerce/products' },
        { name: 'Orders', href: '/ecommerce/orders' },
        { name: 'Credit Card', href: '/ecommerce/credit-card' }
      ]
    },
    { 
      name: 'Extra', 
      type: 'header' 
    },
    { 
      name: 'Documentation', 
      href: '/documentation', 
      icon: 'ri-book-2-fill',
      badge: { text: 'Beta', type: 'secondary' }
    },
    { 
      name: 'Calendar', 
      href: '/calendar', 
      icon: 'ri-calendar-fill' 
    }
  ];

  const toggleMenu = (menuName) => {
    setExpandedMenus(prev => ({
      ...prev,
      [menuName]: !prev[menuName]
    }));
  };

  const isCurrentPath = (path) => {
    return location.pathname === path || location.pathname.startsWith(path + '/');
  };

  const renderMenuItem = (item, level = 0) => {
    if (item.type === 'header') {
      return (
        <li key={item.name} className="menu-header">
          <span>{item.name}</span>
        </li>
      );
    }

    if (item.submenu) {
      return (
        <li 
          key={item.name} 
          className={`menu-item sub-menu ${expandedMenus[item.name] ? 'open' : ''}`}
        >
          <button 
            onClick={() => toggleMenu(item.name)}
            className={`w-full group flex items-center justify-between rounded-md px-2 py-2 text-sm font-medium`}
          >
            <div className="flex items-center">
              {item.icon && (typeof item.icon === 'string' 
                ? <i className={`${item.icon} mr-3`}></i>
                : <item.icon className="mr-3 h-5 w-5 flex-shrink-0" />
              )}
              <span className="menu-title">{item.name}</span>
              {item.badge && (
                <span className="menu-suffix ml-2">
                  <span className={`badge ${item.badge.type}`}>{item.badge.text}</span>
                </span>
              )}
            </div>
            {expandedMenus[item.name] ? (
              <ChevronUp className="h-4 w-4" />
            ) : (
              <ChevronDown className="h-4 w-4" />
            )}
          </button>
          {expandedMenus[item.name] && (
            <div className="sub-menu-list ml-4 mt-1 space-y-1">
              <ul>
                {item.submenu.map(subItem => renderMenuItem(subItem, level + 1))}
              </ul>
            </div>
          )}
        </li>
      );
    }

    return (
      <li key={item.name} className="menu-item">
        <Link
          to={item.href}
          className={`group flex items-center rounded-md px-2 py-2 text-sm ${
            isCurrentPath(item.href) 
              ? 'bg-gray-800 text-white' 
              : 'text-gray-400 hover:bg-gray-800 hover:text-white'
          }`}
        >
          {item.icon && (typeof item.icon === 'string' 
            ? <i className={`${item.icon} mr-3`}></i>
            : <item.icon className="mr-3 h-5 w-5 flex-shrink-0" />
          )}
          <span className="menu-title">{item.name}</span>
          {item.badge && (
            <span className="menu-suffix ml-2">
              <span className={`badge ${item.badge.type}`}>{item.badge.text}</span>
            </span>
          )}
        </Link>
      </li>
    );
  };

  return (
    <div className="flex min-h-screen bg-gray-900">
      <div className={`hidden lg:fixed lg:inset-y-0 lg:flex lg:w-64 lg:flex-col bg-gray-900 border-r border-gray-700 transition-all duration-300 ${
        isSidebarOpen ? 'lg:translate-x-0' : 'lg:-translate-x-full'
      }`}>
        <div className="flex h-full min-h-0 flex-col">
          <div className="flex h-14 items-center border-b border-gray-700 px-4">
            <Link to="/home" className="flex items-center gap-2">
              <span className="text-lg font-semibold text-gray-200">Wiki Paralegal</span>
            </Link>
          </div>
          <nav className="flex-1 space-y-1 px-2 py-4 overflow-y-auto">
            <ul className="menu open-current-submenu">
              {navigation.map(item => renderMenuItem(item))}
              <li className="menu-item">
                <button
                  onClick={logout}
                  className="w-full text-left text-gray-400 hover:bg-gray-800 hover:text-white group flex items-center rounded-md px-2 py-2 text-sm font-medium mt-4"
                >
                  Logout
                </button>
              </li>
            </ul>
          </nav>
        </div>
      </div>

      {/* Mobile menu button and header */}
      <div className="fixed top-0 left-0 right-0 z-40 flex h-14 items-center border-b border-gray-700 bg-gray-900 px-4 lg:hidden">
        <button
          onClick={() => setIsSidebarOpen(!isSidebarOpen)}
          className="text-gray-400 hover:text-gray-200"
        >
          {isSidebarOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
        </button>
        <span className="ml-4 text-lg font-semibold text-gray-200">Wiki Paralegal</span>
      </div>

      {/* Mobile sidebar */}
      <div className={`lg:hidden fixed inset-y-0 left-0 z-50 w-64 bg-gray-900 border-r border-gray-700 transform transition-transform duration-300 ${
        isSidebarOpen ? 'translate-x-0' : '-translate-x-full'
      }`}>
        <div className="flex h-full min-h-0 flex-col">
          <div className="flex h-14 items-center border-b border-gray-700 px-4">
            <Link to="/home" className="flex items-center gap-2">
              <span className="text-lg font-semibold text-gray-200">Wiki Paralegal</span>
            </Link>
          </div>
          <nav className="flex-1 space-y-1 px-2 py-4 overflow-y-auto">
            <ul className="menu open-current-submenu">
              {navigation.map(item => renderMenuItem(item))}
              <li className="menu-item">
                <button
                  onClick={logout}
                  className="w-full text-left text-gray-400 hover:bg-gray-800 hover:text-white group flex items-center rounded-md px-2 py-2 text-sm font-medium mt-4"
                >
                  Logout
                </button>
              </li>
            </ul>
          </nav>
        </div>
      </div>

      {/* Overlay for mobile */}
      {isSidebarOpen && (
        <div 
          className="lg:hidden fixed inset-0 z-40 bg-gray-900/80 transition-opacity duration-300"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Main content */}
      <div className={`flex-1 ${isSidebarOpen ? 'lg:pl-64' : 'lg:pl-0'} transition-all duration-300`}>
        <main className="py-14 px-4 sm:px-6 lg:px-8">
          {children}
        </main>
      </div>
    </div>
  );
};

export default Layout;
